def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.2:
            priority = np.inf
        elif ratio > 1:
            priority = (ratio - 1) * 200 + 10
        else:
            exp_term = 0
            for k in range(1, 6):
                exp_term += ((-1)**k) * (ratio**k) / k
            priority += abs(exp_term)
            if capacity < item * 1.5:
                priority *= 2
            log_component = np.log(capacity + 2) - np.log(item + 1)
            if log_component > 0:
                priority += 5 / log_component
            else:
                priority += 20
            if capacity % 2 == 0:
                priority += 0.3
            else:
                priority -= 0.2
            if ratio < 0.3:
                for m in range(1, 4):
                    priority += ((-1)**m) * (ratio**(m*2)) * m
            if capacity > 5 * item:
                priority -= 1.5
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
